        min: Optional['types.AlertMinAggregateInput'] = None,
        max: Optional['types.AlertMaxAggregateInput'] = None,
        having: Optional['types.AlertScalarWhereWithAggregatesInput'] = None,
        count: Optional[Union[bool, 'types.AlertCountAggregateInput']] = None,
        order: Optional[Union[Mapping['types.AlertScalarFieldKeys', 'types.SortOrder'], List[Mapping['types.AlertScalarFieldKeys', 'types.SortOrder']]]] = None,
